public void enableHeaderActions()
{
    next enableHeaderActions();

    if(salesTable.ETG_IsThirdParty && salesTable.ETG_TPPurchId)
    {
        page.actionPaneControlEnabled(formControlStr(SalesTable, ButtonInterCompanyPurchTableTP), true);
    }
    else
    {
        page.actionPaneControlEnabled(formControlStr(SalesTable, ButtonInterCompanyPurchTableTP), false);
    }

}

/// <summary>
/// Disabling AddLines and AddProducts button  in case of Agreement exists for this order
/// </summary>
/// <param name="args"></param>
[PostHandlerFor(classStr(SalesTableInteraction), methodStr(SalesTableInteraction, salesLine_DS_selectionChanged))]
public static void SalesTableInteraction_Post_salesLine_DS_selectionChanged(XppPrePostArgs args)
{
    SalesTableInteraction   salesTableInteraction   = args.getThis();
    SalesTable              salesTable              = salesTableInteraction.page().activeRecord(identifierStr(SalesTable)) as SalesTable;
    ETG_Parameters          parameters              = ETG_Parameters::find();

    if(parameters.ETG_FrozenValidations == NoYes::Yes
        && parameters.ETG_FrozenValidationSalesOrder == NoYes::Yes)
    {
        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, ButtonLineQuickQuote), salesTable.MatchingAgreement == 0);
        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, RetailAddItemMenuItem), salesTable.MatchingAgreement == 0);
        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, ButtonMarkupTransLine), salesTable.MatchingAgreement == 0);
    }
    ETGACFParameters    ACFParamaters = ETGACFParameters::find();

    if (ACFParamaters.EnableSOWorkflow == NoYes::Yes)
    {
        if (salesTable.ETGWorkflowStatus == VersioningDocumentState::Approved)
        {

        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePickingList), true);;
        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePackingSlip),true);
        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdateInvoice),true);
        }
        else
        {
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePickingList), false);;
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePackingSlip),false);
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdateInvoice),false);
        }

    }
}

/// <summary>
///
/// </summary>
/// <param name="args"></param>
[PostHandlerFor(classStr(SalesTableInteraction), methodStr(SalesTableInteraction, salesTable_DS_selectionChanged))]
public static void SalesTableInteraction_Post_salesTable_DS_selectionChanged(XppPrePostArgs args)
{
    SalesTableInteraction   salesTableInteraction   = args.getThis();
    SalesTable              salesTable              = salesTableInteraction.page().activeRecord(identifierStr(SalesTable)) as SalesTable;
    ETG_Parameters          parameters              = ETG_Parameters::find();

    if(parameters.ETG_FrozenValidations == NoYes::Yes
        && parameters.ETG_FrozenValidationSalesOrder == NoYes::Yes)
    {
        salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, ButtonMarkupTransHeading), salesTable.MatchingAgreement == 0);
    }

    ETGACFParameters    ACFParamaters = ETGACFParameters::find();

    if (ACFParamaters.EnableSOWorkflow == NoYes::Yes)
    {
        if (salesTable.ETGWorkflowStatus == VersioningDocumentState::Approved)
        {

            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePickingList), true);;
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePackingSlip),true);
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdateInvoice),true);
        }
        else
        {
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePickingList), false);;
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdatePackingSlip),false);
            salesTableInteraction.page().actionPaneControlEnabled(formControlStr(SalesTable, buttonUpdateInvoice),false);
        }

    }
}
